export function renderDashboard(d: DashboardData, orgName = 'Living Memory'): string {
  const rootsEmail = process.env.ROOTS_EMAIL ?? 'your-capture-inbox@example.com';
  const seraTipsData = SERA_TIPS.map(t => ({ ...t, text: t.text.replace(/roots@amora\.cr/g, rootsEmail) }));

  // ── Status indicator ────────────────────────────────────────────────────────
  const lastPollAgeMin = d.lastPollAt
    ? (Date.now() - new Date(d.lastPollAt).getTime()) / 60000
    : Infinity;
  const statusClass = lastPollAgeMin < 10 ? 'ok' : lastPollAgeMin < 30 ? 'warn' : 'err';
  const statusText  = lastPollAgeMin < 10 ? 'Online'
    : lastPollAgeMin < 30 ? 'Delayed'
    : d.lastPollAt ? 'Stale' : 'Never polled';

  // ── Queue totals ─────────────────────────────────────────────────────────────
  const queueTotal = Object.values(d.queues).reduce((a, b) => a + b, 0);
  const bannerCls  = queueTotal === 0 ? 'ok' : queueTotal > 20 ? 'err' : 'warn';
  const bannerMsg  = queueTotal === 0
    ? 'All queues clear - nothing awaiting human review.'
    : `${queueTotal} item${queueTotal !== 1 ? 's' : ''} need attention across all queues.`;

  // ── Queue cards ──────────────────────────────────────────────────────────────
  const queueCards = QUEUE_DEFS.map(q => {
    const v   = d.queues[q.key];
    const cls = v === 0 ? 'zero' : v >= 10 ? 'high' : 'warn';
    const url = d.notionUrls[q.dbKey];
    const tag = url ? `a class="q-card" href="${esc(url)}" target="_blank" rel="noopener noreferrer"` : `div class="q-card"`;
    const end = url ? 'a' : 'div';
    return `
    <${tag}>
      <div class="q-label">${q.label}</div>
      <div class="q-value ${cls}">${v}</div>
      <div class="q-desc">${q.desc}${url ? '<span class="q-notion-hint">Open in Notion</span>' : ''}</div>
    </${end}>`;
  }).join('');

  // ── Policy banner ────────────────────────────────────────────────────────────
  const policyOk  = d.policies.missingCircle === 0;
  const policyBnr = policyOk ? 'ok' : 'warn';
  const policyMsg = policyOk
    ? `All ${d.policies.total} policies have a Responsible Circle assigned.`
    : `${d.policies.missingCircle} polic${d.policies.missingCircle !== 1 ? 'ies' : 'y'} still missing a Responsible Circle.`;

  // ── Running since ────────────────────────────────────────────────────────────
  const rsd = d.metrics.runningSinceDays;
  const runningSinceStr = rsd === null ? 'N/A'
    : rsd === 0 ? 'Today'
    : rsd < 30  ? `${rsd}d`
    : `${Math.round(rsd / 30)}mo`;

  // ── Access failures table ────────────────────────────────────────────────────
  const failuresHtml = d.accessFailures.length === 0
    ? '<p class="dim">No assets in Manual Review.</p>'
    : `<table><thead><tr><th>Asset</th><th>Type</th><th>Retries</th><th>Error</th><th></th></tr></thead><tbody>
        ${d.accessFailures.map(f => `
          <tr>
            <td>${f.driveLink ? `<a href="${esc(f.driveLink)}" target="_blank">${esc(f.assetName)}</a>` : esc(f.assetName)}</td>
            <td>${esc(f.assetType)}</td>
            <td>${f.retryCount}</td>
            <td class="errtxt">${esc(f.errorMessage)}</td>
            <td>
              <form method="POST" action="/retry/${esc(f.id)}" onsubmit="return confirm('Reset this asset for retry?')">
                <button class="btn">Retry</button>
              </form>
            </td>
          </tr>`).join('')}
      </tbody></table>`;

  // ── Role health panel ────────────────────────────────────────────────────────
  const vacantCount  = d.roleHealth.filter(r => r.issue === 'vacant').length;
  const expiringCount = d.roleHealth.filter(r => r.issue === 'expiring').length;
  const roleHealthHtml = d.roleHealth.length === 0
    ? '<p class="dim">All active roles are filled and no terms expire in the next 30 days.</p>'
    : `<div class="rh-grid">${d.roleHealth.map(r => `
    <div class="rh-item">
      <span class="rh-badge ${r.issue}">${r.issue === 'vacant' ? 'Vacant' : 'Term Expiring'}</span>
      <div class="rh-role">${esc(r.roleName)}</div>
      <div class="rh-circle">${esc(r.circleName)}${r.expiresAt ? ` - expires ${esc(r.expiresAt)}` : ''}</div>
    </div>`).join('')}</div>`;

  const errorsHtml = d.recentErrors.length === 0
    ? '<p class="dim">No recent errors.</p>'
    : `<table><thead><tr><th>Error</th><th>When</th></tr></thead><tbody>
        ${d.recentErrors.map(e => `
          <tr>
            <td class="errtxt">${esc(e.error)}</td>
            <td class="dim">${fmt(e.startedAt)}</td>
          </tr>`).join('')}
      </tbody></table>`;

  // ── Activity log ──────────────────────────────────────────────────────────────
  const activityLogHtml = d.recentActivity.length === 0
    ? '<p class="dim">No recent activity to show.</p>'
    : `<div class="activity-feed">${d.recentActivity.map(a => {
        const statusCls = a.status === 'Success' ? 'ok' : a.status === 'Error' ? 'err' : 'warn';
        const tokens = a.tokenEstimate > 0 ? `<span class="act-meta">${a.tokenEstimate.toLocaleString()} tokens</span>` : '';
        const errMsg  = a.error ? `<div class="act-error">${esc(a.error.slice(0, 120))}</div>` : '';
        return `<div class="act-row">
          <div class="act-dot ${statusCls}"></div>
          <div class="act-body">
            <div class="act-top">
              <span class="act-type">${esc(a.eventType)}</span>
              ${tokens}
            </div>
            ${errMsg}
          </div>
          <div class="act-time dim">${fmt(a.startedAt)}</div>
        </div>`;
      }).join('')}</div>`;

  // ── Chart data (server-side JSON, safe — all values are numbers/strings from Notion) ─
  const activityJson = JSON.stringify(
    d.metrics.weeklyActivity.map(a => ({ count: a.count, label: dayLabel(a.date) })),
  );
  const typeTotal = Object.values(d.metrics.emailTypeBreakdown).reduce((a, b) => a + b, 0);
  const typeJson  = JSON.stringify(d.metrics.emailTypeBreakdown);

  return `<!DOCTYPE html>
<html lang="en" data-theme="dark">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Sera | ${orgName}</title>
<script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js"></script>
<style>${CSS}</style>
</head>
<body>

<header>
  <div class="header-left">
    <span class="header-logo">Sera <span>· ${orgName}</span></span>
    <span class="status-dot ${statusClass}"></span>
    <span class="status-label">${statusText}</span>
  </div>
  <div class="header-right">
    <span class="header-meta">${d.fromCache ? `Cached ${d.cacheAgeSeconds}s ago` : `Live ${fmt(d.fetchedAt)}`}</span>
    <button class="btn-ghost" onclick="toggleTheme()" id="theme-btn">Light</button>
    <a href="/" class="btn-ghost" style="text-decoration:none">Reload</a>
    <button class="btn-ghost" onclick="signOut()">Sign Out</button>
  </div>
</header>

<div class="wrap">

  <!-- ── Hero metrics ────────────────────────────────────── -->
  <div class="hero-grid">
    <div class="hero-card g1">
      <div class="hero-label">Est. Hours Saved</div>
      <div class="hero-value counter" data-target="${d.metrics.estimatedHoursSaved}">${num(d.metrics.estimatedHoursSaved)}</div>
      <div class="hero-sub">meetings + emails + tasks combined</div>
    </div>
    <div class="hero-card g2">
      <div class="hero-label">Emails Processed</div>
      <div class="hero-value counter" data-target="${d.metrics.emailsProcessed}">${num(d.metrics.emailsProcessed)}</div>
      <div class="hero-sub">filed, extracted, and remembered</div>
    </div>
    <div class="hero-card g3">
      <div class="hero-label">Meetings Captured</div>
      <div class="hero-value counter" data-target="${d.community.totalMeetings}">${num(d.community.totalMeetings)}</div>
      <div class="hero-sub">recordings, transcripts &amp; notes</div>
    </div>
    <div class="hero-card g4">
      <div class="hero-label">People Known</div>
      <div class="hero-value counter" data-target="${d.community.totalProfiles}">${num(d.community.totalProfiles)}</div>
      <div class="hero-sub">profiles auto-built from email</div>
    </div>
  </div>

  <!-- ── Charts ──────────────────────────────────────────── -->
  <div class="chart-grid">
    <div class="chart-card">
      <h2>Emails Processed - Last 7 Days</h2>
      <div class="chart-wrap"><canvas id="activityChart"></canvas></div>
    </div>
    <div class="chart-card">
      <h2>Email Intake Breakdown</h2>
      ${typeTotal > 0
        ? '<div class="chart-wrap"><canvas id="typeChart"></canvas></div>'
        : '<div class="chart-empty">No emails processed yet</div>'}
    </div>
  </div>

  <!-- ── Sera tips ──────────────────────────────────────── -->
  <div class="sera-panel" id="sera-panel">
    <div class="sera-avatar-wrap" id="sera-avatar-wrap">${SERA_AVATAR_IMG}</div>
    <div class="sera-body">
      <span class="sera-badge" id="sera-badge"></span>
      <div class="sera-tip-text" id="sera-tip"></div>
      <div class="sera-dots" id="sera-dots">
        ${seraTipsData.map((_, i) => `<div class="sera-dot${i === 0 ? ' active' : ''}" onclick="showTip(${i})"></div>`).join('')}
      </div>
    </div>
  </div>

  <!-- ── Review queues ───────────────────────────────────── -->
  <section>
    <h2>Review Queues</h2>
    <div class="banner ${bannerCls}">${bannerMsg}</div>
    <div class="queue-grid">${queueCards}</div>
  </section>

  <!-- ── Sub-stats row ───────────────────────────────────── -->
  <div class="stat-grid" style="margin-bottom:20px">
    <div class="stat-card">
      <div class="s-label">Tasks Extracted</div>
      <div class="s-value">${num(d.metrics.totalTasks)}</div>
      <div class="s-sub">across all sources</div>
    </div>
    <div class="stat-card">
      <div class="s-label">Decisions Tracked</div>
      <div class="s-value">${num(d.metrics.totalDecisions)}</div>
      <div class="s-sub">candidates + confirmed</div>
    </div>
    <div class="stat-card">
      <div class="s-label">Active Circles</div>
      <div class="s-value">${d.community.activeCircles}</div>
      <div class="s-sub">CCOS governance circles</div>
    </div>
    <div class="stat-card">
      <div class="s-label">Risks Tracked</div>
      <div class="s-value">${num(d.community.totalRisks)}</div>
      <div class="s-sub">total logged</div>
    </div>
    <div class="stat-card">
      <div class="s-label">Open Risks</div>
      <div class="s-value ${d.community.openRisks > 0 ? 'warn' : ''}">${num(d.community.openRisks)}</div>
      <div class="s-sub">${d.queues.highRisks} high severity</div>
    </div>
    ${d.systemConfig.kbEnabled ? `<div class="stat-card">
      <div class="s-label">KB Articles</div>
      <div class="s-value">${num(d.metrics.totalKbArticles)}</div>
      <div class="s-sub">${d.queues.kbDrafts} drafts pending</div>
    </div>` : ''}
  </div>

  <!-- ── Role health ───────────────────────────────────── -->
  <section>
    <h2>Role Health - Vacant &amp; Expiring Terms</h2>
    <div class="banner ${d.roleHealth.length === 0 ? 'ok' : vacantCount > 0 ? 'err' : 'warn'}">
      ${d.roleHealth.length === 0
        ? 'All active roles are filled and no terms expire within 30 days.'
        : `${vacantCount > 0 ? `${vacantCount} vacant role${vacantCount !== 1 ? 's' : ''} need filling. ` : ''}${expiringCount > 0 ? `${expiringCount} term${expiringCount !== 1 ? 's' : ''} expiring within 30 days.` : ''}`
      }
    </div>
    ${roleHealthHtml}
  </section>

  <!-- ── Policy library ─────────────────────────────────── -->
  <section>
    <h2>Policy Library</h2>
    <div class="banner ${policyBnr}">${policyMsg}</div>
    <div class="stat-grid">
      <a class="stat-card" href="${d.notionUrls.policies}" target="_blank" rel="noopener" style="text-decoration:none;color:inherit;display:block">
        <div class="s-label" style="display:flex;align-items:center;gap:4px">Total Policies <svg width="10" height="10" viewBox="0 0 10 10" fill="none" style="opacity:.5"><path d="M1 9L9 1M9 1H4M9 1V6" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg></div>
        <div class="s-value">${d.policies.total}</div>
      </a>
      <div class="stat-card">
        <div class="s-label">Draft</div>
        <div class="s-value">${d.policies.draft}</div>
        <div class="s-sub">Awaiting ratification</div>
      </div>
      <div class="stat-card">
        <div class="s-label">Active</div>
        <div class="s-value">${d.policies.active}</div>
        <div class="s-sub">In effect</div>
      </div>
      <div class="stat-card">
        <div class="s-label">Missing Circle</div>
        <div class="s-value ${d.policies.missingCircle > 0 ? 'warn' : ''}">${d.policies.missingCircle}</div>
        <div class="s-sub">Need Responsible Circle</div>
      </div>
    </div>
  </section>

  <!-- ── Access failures ─────────────────────────────────── -->
  <section>
    <h2>Drive Access Failures - Manual Review (${d.accessFailures.length})</h2>
    ${failuresHtml}
  </section>

  <!-- ── Activity log ──────────────────────────────────────── -->
  <section>
    <h2>Recent Activity</h2>
    ${activityLogHtml}
  </section>

  <!-- ── System health ───────────────────────────────────── -->
  <section>
    <h2>System Health</h2>
    <div class="health-grid">
      <div class="h-card">
        <div class="h-label">Last Successful Poll</div>
        <div class="h-value ${d.lastPollAt ? 'ok' : 'warn'}">${fmt(d.lastPollAt)}</div>
      </div>
      <div class="h-card">
        <div class="h-label">Processed This Week</div>
        <div class="h-value ok">${d.community.processedThisWeek} events</div>
      </div>
    </div>
    <h2>Recent Errors</h2>
    ${errorsHtml}
  </section>

  <!-- ── System settings ─────────────────────────────────── -->
  <section>
    <h2>System Configuration</h2>
    <div class="cfg-grid">
      <div class="cfg-item">
        <div class="cfg-label">AI Model</div>
        <div class="cfg-value mono">${esc(d.systemConfig.claudeModel)}</div>
      </div>
      <div class="cfg-item">
        <div class="cfg-label">Poll Interval</div>
        <div class="cfg-value">${d.systemConfig.pollIntervalSeconds}s (${Math.round(d.systemConfig.pollIntervalSeconds / 60)} min)</div>
      </div>
      <div class="cfg-item">
        <div class="cfg-label">Max Retry Count</div>
        <div class="cfg-value">${d.systemConfig.maxRetryCount}</div>
      </div>
      <div class="cfg-item">
        <div class="cfg-label">Tenant</div>
        <div class="cfg-value mono">${esc(d.systemConfig.tenantId)}</div>
      </div>
      <div class="cfg-item">
        <div class="cfg-label">Admin Notifications</div>
        <div class="cfg-value mono" style="font-size:11px">${esc(d.systemConfig.adminEmail)}</div>
      </div>
    </div>
    <p class="dim" style="margin-top:14px">To change these settings, update the corresponding Railway environment variables and redeploy.</p>
  </section>

</div>

<footer>
  <span>Sera &nbsp;·&nbsp; ${orgName} &nbsp;·&nbsp; Running ${runningSinceStr} &nbsp;·&nbsp; 3-min poll cycle &nbsp;·&nbsp; All data from Notion</span>
</footer>

<!-- Embedded chart data (server-rendered, no XHR needed) -->
<script id="activity-data" type="application/json">${activityJson}</script>
<script id="type-data" type="application/json">${typeJson}</script>

<script>
(function(){
  // ── Theme ─────────────────────────────────────────────────────────────────
  var saved = localStorage.getItem('lm-theme') || 'dark';
  document.documentElement.setAttribute('data-theme', saved);
  document.getElementById('theme-btn').textContent = saved === 'dark' ? 'Light' : 'Dark';

  // Hit /logout with bogus credentials so the browser discards its cached Basic Auth credentials,
  // then navigate to / which re-triggers the login prompt.
  window.signOut = function(){
    fetch('/logout', { headers: { 'Authorization': 'Basic ' + btoa('logout:logout') } })
      .finally(function(){ window.location.href = '/'; });
  };

  window.toggleTheme = function(){
    var cur  = document.documentElement.getAttribute('data-theme') || 'dark';
    var next = cur === 'dark' ? 'light' : 'dark';
    document.documentElement.setAttribute('data-theme', next);
    localStorage.setItem('lm-theme', next);
    document.getElementById('theme-btn').textContent = next === 'dark' ? 'Light' : 'Dark';
    buildCharts();
  };

  // ── Counter animation ─────────────────────────────────────────────────────
  function animateCounters(){
    document.querySelectorAll('.counter').forEach(function(el){
      var target = parseInt(el.getAttribute('data-target') || '0', 10);
      if(target === 0){ el.textContent = '0'; return; }
      var start = performance.now();
      var dur   = Math.min(1800, 400 + target * 0.4);
      function tick(now){
        var p = Math.min((now - start) / dur, 1);
        var ease = 1 - Math.pow(1 - p, 3);
        el.textContent = Math.floor(ease * target).toLocaleString();
        if(p < 1) requestAnimationFrame(tick);
      }
      requestAnimationFrame(tick);
    });
  }

  // ── Charts ────────────────────────────────────────────────────────────────
  var activityData = JSON.parse(document.getElementById('activity-data').textContent);
  var typeDataRaw  = JSON.parse(document.getElementById('type-data').textContent);
  var actChart, typeChart;

  function isDark(){ return document.documentElement.getAttribute('data-theme') !== 'light'; }

  function chartColors(){
    var dark = isDark();
    return {
      bar:        dark ? 'rgba(99,102,241,0.75)' : 'rgba(79,70,229,0.75)',
      barHover:   dark ? '#6366f1' : '#4f46e5',
      grid:       dark ? 'rgba(255,255,255,0.07)' : 'rgba(0,0,0,0.07)',
      tick:       dark ? '#6b7a96' : '#64748b',
      donut:      ['#6366f1','#10b981','#f59e0b','#3b82f6','#ec4899'],
      legendText: dark ? '#9ca3af' : '#64748b',
    };
  }

  function buildCharts(){
    var c  = chartColors();
    var dark = isDark();
    Chart.defaults.color = c.tick;

    // Activity bar chart
    var actCtx = document.getElementById('activityChart');
    if(actCtx){
      if(actChart) actChart.destroy();
      actChart = new Chart(actCtx, {
        type: 'bar',
        data: {
          labels: activityData.map(function(d){ return d.label; }),
          datasets:[{
            label: 'Items processed',
            data: activityData.map(function(d){ return d.count; }),
            backgroundColor: c.bar,
            hoverBackgroundColor: c.barHover,
            borderRadius: 5,
            borderSkipped: false,
          }]
        },
        options:{
          responsive:true, maintainAspectRatio:false,
          plugins:{ legend:{ display:false } },
          scales:{
            y:{ beginAtZero:true, ticks:{ color:c.tick, precision:0 }, grid:{ color:c.grid }, border:{ display:false } },
            x:{ ticks:{ color:c.tick }, grid:{ display:false }, border:{ display:false } }
          }
        }
      });
    }

    // Type doughnut chart
    var typeCtx = document.getElementById('typeChart');
    if(typeCtx){
      if(typeChart) typeChart.destroy();
      var labels = ['Recordings','Transcripts','Notes','Operational','Forwarded'];
      var vals   = [typeDataRaw.recordings, typeDataRaw.transcripts, typeDataRaw.notes, typeDataRaw.operational, typeDataRaw.forwarded];
      typeChart = new Chart(typeCtx, {
        type: 'doughnut',
        data:{
          labels: labels,
          datasets:[{ data: vals, backgroundColor: c.donut, borderWidth:0, hoverOffset:4 }]
        },
        options:{
          responsive:true, maintainAspectRatio:false, cutout:'62%',
          plugins:{ legend:{ position:'bottom', labels:{ color:c.legendText, padding:10, font:{ size:11 }, boxWidth:12 } } }
        }
      });
    }
  }

  if(typeof Chart !== 'undefined'){
    buildCharts();
  } else {
    document.querySelectorAll('.chart-wrap').forEach(function(el){
      el.innerHTML = '<div class="chart-empty">Chart.js unavailable</div>';
    });
  }

  animateCounters();

  // ── Sera tips rotation ────────────────────────────────────────────────────
  var seraTips = ${JSON.stringify(seraTipsData)};
  var seraCurrent = 0;
  var seraTimer;

  function badgeClass(badge) {
    if (badge === 'Did You Know?') return 'didyouknow';
    if (badge === 'Pro Tip') return 'protip';
    return 'tip';
  }

  window.showTip = function(idx) {
    clearInterval(seraTimer);
    seraCurrent = ((idx % seraTips.length) + seraTips.length) % seraTips.length;
    var tipEl   = document.getElementById('sera-tip');
    var badgeEl = document.getElementById('sera-badge');
    var dots    = document.querySelectorAll('.sera-dot');
    if (!tipEl || !badgeEl) return;
    tipEl.classList.remove('visible');
    setTimeout(function() {
      var t = seraTips[seraCurrent];
      badgeEl.textContent  = t.badge;
      badgeEl.className    = 'sera-badge ' + badgeClass(t.badge);
      tipEl.innerHTML      = t.text;
      tipEl.classList.add('visible');
      dots.forEach(function(d, i) { d.classList.toggle('active', i === seraCurrent); });
    }, 200);
    seraTimer = setInterval(function() { window.showTip(seraCurrent + 1); }, 12000);
  };

  window.showTip(Math.floor(Math.random() * seraTips.length));

  // ── Sera tilt (desktop: mouse, mobile: gyro) ──────────────────────────────
  (function() {
    var wrap = document.getElementById('sera-avatar-wrap');
    var img  = wrap && wrap.querySelector('.sera-avatar');
    if (!img) return;

    function applyTilt(rx, ry) {
      // clamp to ±10deg X, ±14deg Y
      rx = Math.max(-10, Math.min(10, rx));
      ry = Math.max(-14, Math.min(14, ry));
      img.style.transform = 'perspective(180px) rotateX(' + rx + 'deg) rotateY(' + ry + 'deg) scale(1.08)';
    }
    function resetTilt() {
      img.style.transform = '';
    }

    var isMobile = /Mobi|Android|iPhone|iPad/i.test(navigator.userAgent);

    if (!isMobile) {
      // Desktop: cursor position drives the tilt
      document.addEventListener('mousemove', function(e) {
        var cx = window.innerWidth  / 2;
        var cy = window.innerHeight / 2;
        var rx = -((e.clientY - cy) / cy) * 10;
        var ry =  ((e.clientX - cx) / cx) * 14;
        applyTilt(rx, ry);
      });
      document.addEventListener('mouseleave', resetTilt);
    } else {
      // Mobile: device gyroscope drives the tilt
      if (window.DeviceOrientationEvent) {
        window.addEventListener('deviceorientation', function(e) {
          if (e.beta === null) return;
          var rx = ((e.beta  - 45) / 45) * 10;
          var ry = (e.gamma        / 45) * 14;
          applyTilt(rx, ry);
        });
      }
      // Tap the avatar for a fun wink animation
      wrap.addEventListener('click', function() {
        img.style.transition = 'transform .06s ease-out';
        img.style.transform = 'perspective(180px) scaleY(0.05) scaleX(1.05)';
        setTimeout(function() {
          img.style.transform = 'perspective(180px) scaleY(1.1) scaleX(0.97)';
          setTimeout(function() {
            img.style.transform = '';
            img.style.transition = 'transform .08s ease-out';
          }, 100);
        }, 80);
      });
    }
  })();
})();
</script>
</body>
</html>`;
}
